// -----------------------------------------------------------------------------
// RTOSAlgorithm-style class implementation
// -----------------------------------------------------------------------------

ridgeBaseCompareDynamics::ridgeBaseCompareDynamics()
{
	m_NumJoints = 7;
	m_gx = 9.8100000000000005;
	m_gy = 0;
	m_gz = 0;
	m_zeros.assign(m_NumJoints, 0.0);
}

ridgeBaseCompareDynamics::~ridgeBaseCompareDynamics()
{
}

void ridgeBaseCompareDynamics::setRobotDHParameters
(
	const EcRealVector& kinematcisParam
)
{
	// Geometry is fixed by the URDF used during code generation.
	// Keep this method for compatibility with dynamicsBase callers.
	(void)kinematcisParam;
}

void ridgeBaseCompareDynamics::setGravityVector
(
	const EcReal gx, const EcReal gy, const EcReal gz
)
{
	m_gx = gx;
	m_gy = gy;
	m_gz = gz;
}

void ridgeBaseCompareDynamics::calculateGravityJointTorques
(
	const EcRealVector& q,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	(void)parms;
	if (q.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	const double gravity[3] = {m_gx, m_gy, m_gz};
	calculateIdentifiedGravityTorqueCore(q.data(), gravity, tau.data());
}

void ridgeBaseCompareDynamics::computeRigidTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	const double gravity[3] = {m_gx, m_gy, m_gz};
	calculateIdentifiedRigidDynamicsCore(q.data(), dq.data(), ddq.data(), gravity, tau.data());
}

void ridgeBaseCompareDynamics::computeMassTorque
(
	const EcRealVector& q,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	calculateIdentifiedMassTorqueCore(q.data(), ddq.data(), tau.data());
}

void ridgeBaseCompareDynamics::computeCoriolisTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	calculateIdentifiedCoriolisTorqueCore(q.data(), dq.data(), tau.data());
}

void ridgeBaseCompareDynamics::computeGravityAxisTorques
(
	const EcRealVector& q,
	EcRealVector& tauGxUnit,
	EcRealVector& tauGyUnit,
	EcRealVector& tauGzUnit
) const
{
	if (q.size() != m_NumJoints)
	{
		return;
	}
	if (tauGxUnit.size() != m_NumJoints)
	{
		tauGxUnit.assign(m_NumJoints, 0.0);
	}
	if (tauGyUnit.size() != m_NumJoints)
	{
		tauGyUnit.assign(m_NumJoints, 0.0);
	}
	if (tauGzUnit.size() != m_NumJoints)
	{
		tauGzUnit.assign(m_NumJoints, 0.0);
	}
	calculateIdentifiedGravityXAxisTorqueCore(q.data(), tauGxUnit.data());
	calculateIdentifiedGravityYAxisTorqueCore(q.data(), tauGyUnit.data());
	calculateIdentifiedGravityZAxisTorqueCore(q.data(), tauGzUnit.data());
}

void ridgeBaseCompareDynamics::computeFrictionTorque
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	EcRealVector total(m_NumJoints, 0.0);
	EcRealVector rigid(m_NumJoints, 0.0);
	computeInverseDynamics(q, dq, ddq, total);
	computeRigidTorque(q, dq, ddq, rigid);
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	for (EcSizeT idx = 0; idx < m_NumJoints; ++idx)
	{
		tau[idx] = total[idx] - rigid[idx];
	}
}

void ridgeBaseCompareDynamics::computeInverseDynamics
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	EcRealVector& tau
) const
{
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}
	const double gravity[3] = {m_gx, m_gy, m_gz};
	calculateIdentifiedInverseDynamicsCore(q.data(), dq.data(), ddq.data(), gravity, tau.data());
}

EcBoolean ridgeBaseCompareDynamics::calculateEstimateJointToqrues
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	(void)parms;  // Identified parameters are baked into the generated formula.
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return false;
	}
	computeInverseDynamics(q, dq, ddq, tau);
	return true;
}

void ridgeBaseCompareDynamics::calculateMomentumEstimatedJointTorques
(
	const EcRealVector& q,
	const EcRealVector& dq,
	const EcRealVector& ddq,
	const EcRealVector& parms,
	EcRealVector& tau
)
{
	(void)parms;
	if (q.size() != m_NumJoints || dq.size() != m_NumJoints || ddq.size() != m_NumJoints)
	{
		return;
	}
	if (tau.size() != m_NumJoints)
	{
		tau.assign(m_NumJoints, 0.0);
	}

	calculateIdentifiedZeroGravityRigidTorqueCore(q.data(), dq.data(), ddq.data(), tau.data());
}
